"use client";

import { useRef, useState } from "react";

// shadcn
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import {
  Carousel,
  CarouselApi,
  CarouselContent,
  CarouselItem,
} from "@/components/ui/carousel";

// constants
const testimonials = [
  {
    name: "Shirley Hoe",
    role: "Manager at Apple",
    image: "https://cdn.uiable.com/block/user13.png",
    initials: "SH",
    content:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led way to an adjoining hall.",
  },
  {
    name: "Joseph William",
    role: "Manager at Apple",
    image: "https://cdn.uiable.com/block/user14.png",
    initials: "JW",
    content:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led way to an adjoining hall.",
  },
  {
    name: "John Doe",
    role: "Manager at Apple",
    image: "https://cdn.uiable.com/block/user15.png",
    initials: "JD",
    content:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led way to an adjoining hall.",
  },
];

//  ------------------------------ | TESTIMONIAL 5 | ------------------------------  //

export default function Testimonial5() {
  const [active, setActive] = useState(0);
  const carouselApiRef = useRef<CarouselApi | null>(null);

  return (
    <section className="py-12 sm:py-16 md:py-20 lg:py-28">
      <div className="container mx-auto px-4">
        <div className="grid grid-cols-12 gap-8">
          <div className="col-span-12 flex flex-col items-center">
            <h2 className="text-center text-xl sm:text-2xl md:text-3xl lg:text-4xl">
              What Clients Say
            </h2>
            <p className="mt-3 sm:mt-4 max-w-xl text-center text-muted-foreground text-sm sm:text-base md:text-lg">
              {testimonials[active].description}
            </p>
            <Carousel
              className="relative mt-8 sm:mt-10 w-full max-w-xl sm:max-w-2xl md:max-w-3xl mx-auto"
              opts={{ loop: true }}
              setApi={(api) => {
                if (!api) return;
                carouselApiRef.current = api;
                api.on("select", () => {
                  setActive(api.selectedScrollSnap());
                });
              }}
            >
              <CarouselContent>
                {testimonials.map((testimonial) => (
                  <CarouselItem key={testimonial.name}>
                    <p className="text-center text-lg sm:text-xl md:text-2xl lg:text-3xl font-semibold min-h-16 flex items-center justify-center px-2 sm:px-4">
                      {testimonial.content}
                    </p>
                  </CarouselItem>
                ))}
              </CarouselContent>
              {/* CarouselPrevious and CarouselNext removed as per user request */}
            </Carousel>
            <div className="mt-10 sm:mt-14 flex flex-col sm:flex-row sm:items-end gap-6 sm:gap-12 w-full max-w-md sm:max-w-4xl mx-auto justify-center">
              {testimonials.map((testimonial, idx) => (
                <div
                  key={testimonial.name}
                  className={`flex flex-col items-center cursor-pointer transition-opacity ${active === idx ? "opacity-100" : "opacity-60"} w-full sm:w-auto sm:min-w-55`}
                  onClick={() => {
                    setActive(idx);
                    if (carouselApiRef.current) {
                      carouselApiRef.current.scrollTo(idx);
                    }
                  }}
                >
                  <Avatar size="lg">
                    <AvatarImage
                      src={testimonial.image}
                      alt={testimonial.name}
                    />
                    <AvatarFallback>{testimonial.initials}</AvatarFallback>
                  </Avatar>
                  <div className="mt-3 text-base font-medium text-center">
                    {testimonial.name}
                  </div>
                  <div className="text-sm text-muted-foreground text-center">
                    {testimonial.role}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
